以下用本節代表題 1584. 連接所有點的最小費用 展示核心寫法。

**完整題目**：給定平面上的點，兩點連線成本為曼哈頓距離，求連通所有點的最小總成本。

**想到本 Pattern 的線索**：題目描述可達、路徑、依賴或關係傳遞；把物件當節點、操作當邊後，就能選遍歷或最短路。

```cpp
class Solution {
public:
    int minCostConnectPoints(vector<vector<int>>& points) {
        int n = points.size(), ans = 0;
        vector<int> minDist(n, INT_MAX);
        vector<char> used(n);
        minDist[0] = 0;
        for (int it = 0; it < n; ++it) {
            int u = -1;
            for (int i = 0; i < n; ++i) {
                if (!used[i] && (u == -1 || minDist[i] < minDist[u])) u = i;
            }
            used[u] = true;
            ans += minDist[u];
            for (int v = 0; v < n; ++v) {
                int w = abs(points[u][0] - points[v][0]) + abs(points[u][1] - points[v][1]);
                if (!used[v]) minDist[v] = min(minDist[v], w);
            }
        }
        return ans;
    }
};
```

