class Solution {
public:
    int findCircleNum(vector<vector<int>>& isConnected) {
        int n = isConnected.size(), ans = 0;
        vector<char> vis(n);
        function<void(int)> dfs = [&](int u) {
            vis[u] = true;
            for (int v = 0; v < n; ++v) {
                if (isConnected[u][v] && !vis[v]) dfs(v);
            }
        };
        for (int i = 0; i < n; ++i) {
            if (!vis[i]) {
                ans++;
                dfs(i);
            }
        }
        return ans;
    }
};
```

