**完整題目**：給定無向圖，判斷是否能把所有節點分成兩組，使每條邊兩端位於不同組。

**想到本 Pattern 的線索**：題目描述可達、路徑、依賴或關係傳遞；把物件當節點、操作當邊後，就能選遍歷或最短路。

```cpp
class Solution {
public:
    bool isBipartite(vector<vector<int>>& graph) {
        int n = graph.size();
        vector<int> color(n, -1);
        for (int i = 0; i < n; ++i) {
            if (color[i] != -1) continue;
            queue<int> q;
            q.push(i);
            color[i] = 0;
            while (!q.empty()) {
                int u = q.front(); q.pop();
                for (int v : graph[u]) {
                    if (color[v] == -1) {
                        color[v] = color[u] ^ 1;
                        q.push(v);
                    } else if (color[v] == color[u]) {
                        return false;
                    }
                }
            }
        }
        return true;
    }
};
```

